	(2, '用户管理-账号初始密码', 'sys.user.initPassword', '123456', 'Y', 'admin', '2026-01-04 20:14:12', '', NULL, '初始化密码 123456'),
	(3, '主框架页-侧边栏主题', 'sys.index.sideTheme', 'theme-dark', 'Y', 'admin', '2026-01-04 20:14:12', 'wyx', '2026-01-05 21:22:48', '深色主题theme-dark，浅色主题theme-light'),
	(4, '账号自助-验证码开关', 'sys.account.captchaEnabled', 'true', 'Y', 'admin', '2026-01-04 20:14:12', 'wyx', '2026-04-16 16:24:28', '是否开启验证码功能（true开启，false关闭）'),
